async addToCart(userId: number, productId: number, variationId: number, quantity: number) {
  let cart = await this.cartRepo.findOne({ where: { user: { id: userId } }, relations: ['items', 'items.productVariation'] });
  if (!cart) {
    cart = this.cartRepo.create({ user: { id: userId }, items: [] });
  }
  const existingItem = cart.items.find(item => item.productVariation.id === variationId);
  if (existingItem) {
    existingItem.quantity += quantity;
  } else {
    const variation = await this.variationRepo.findOneBy({ id: variationId });
    cart.items.push(this.cartItemRepo.create({ cart, productVariation: variation, quantity }));
  }
  return this.cartRepo.save(cart);
}
