async updateCartItemQuantity(userId: number, itemId: number, newQuantity: number) {
  const cart = await this.cartRepo.findOne({ where: { user: { id: userId } }, relations: ['items'] });
  if (!cart) throw new NotFoundException('Panier non trouvé');
  const item = cart.items.find(i => i.id === itemId);
  if (!item) throw new NotFoundException('Item non trouvé');
  if (newQuantity <= 0) {
    cart.items = cart.items.filter(i => i.id !== itemId);
  } else {
    item.quantity = newQuantity;
  }
  await this.cartRepo.save(cart);
  return this.getCart(userId);
}
