async mergeCarts(userId: number, anonymousCartItems: CartItemDto[]) {
  let userCart = await this.cartRepo.findOne({ where: { user: { id: userId } }, relations: ['items', 'items.productVariation'] });
  if (!userCart) {
    userCart = this.cartRepo.create({ user: { id: userId }, items: [] });
  }
  for (const anonItem of anonymousCartItems) {
    const existing = userCart.items.find(item => item.productVariation.id === anonItem.variationId);
    if (existing) {
      existing.quantity += anonItem.quantity;
    } else {
      const variation = await this.variationRepo.findOneBy({ id: anonItem.variationId });
      userCart.items.push(this.cartItemRepo.create({ cart: userCart, productVariation: variation, quantity: anonItem.quantity }));
    }
  }
  await this.cartRepo.save(userCart);
  return userCart;
}
