@Controller('cart')
@UseGuards(JwtAuthGuard)
export class CartController {
  constructor(private cartService: CartService) {}

  @Get()
  getCart(@Req() req: RequestWithUser) {
    return this.cartService.getCart(req.user.id);
  }

  @Post('items')
  addItem(@Req() req: RequestWithUser, @Body() addItemDto: AddItemDto) {
    return this.cartService.addToCart(req.user.id, addItemDto.variationId, addItemDto.quantity);
  }

  @Patch('items/:id')
  updateQuantity(@Req() req: RequestWithUser, @Param('id') itemId: number, @Body('quantity') quantity: number) {
    return this.cartService.updateCartItemQuantity(req.user.id, itemId, quantity);
  }

  @Delete('items/:id')
  removeItem(@Req() req: RequestWithUser, @Param('id') itemId: number) {
    return this.cartService.removeCartItem(req.user.id, itemId);
  }

  @Delete()
  clearCart(@Req() req: RequestWithUser) {
    return this.cartService.clearCart(req.user.id);
  }
}
