async loginWithCartMerge(loginDto: LoginDto, anonymousCart: CartItemDto[]) {
  const user = await this.validateUser(loginDto.email, loginDto.password);
  const token = this.jwtService.sign({ sub: user.id, roles: user.roles });

  if (anonymousCart && anonymousCart.length > 0) {
    await this.cartService.mergeCarts(user.id, anonymousCart);
  }

  const updatedCart = await this.cartService.getCart(user.id);
  return { accessToken: token, cart: updatedCart };
}
